// Extrai dados da mensagem do WhatsApp Cloud API
const body = $input.first().json.body || $input.first().json;

// Verifica se é verificação do webhook Meta
if (body['hub.mode'] === 'subscribe') {
  return [{ json: { type: 'verification', challenge: body['hub.challenge'] } }];
}

// Extrai a mensagem
try {
  const entry = body.entry?.[0];
  const change = entry?.changes?.[0];
  const value = change?.value;
  const message = value?.messages?.[0];
  const contact = value?.contacts?.[0];

  if (!message) {
    return [{ json: { type: 'no_message' } }];
  }

  return [{
    json: {
      type: 'message',
      phone: message.from,
      name: contact?.profile?.name || 'Paciente',
      messageId: message.id,
      text: message.text?.body || '',
      messageType: message.type,
      timestamp: message.timestamp,
      phoneNumberId: value.metadata?.phone_number_id,
    }
  }];
} catch(e) {
  return [{ json: { type: 'error', error: e.message } }];
}

// Determina o fluxo baseado na mensagem do paciente
const text = ($json.text || '').toLowerCase().trim();
const phone = $json.phone;
const name = $json.name;

let fluxo = 'saudacao';

// Detectar intenção
if (/^(oi|olá|ola|bom dia|boa tarde|boa noite|hello|hi|oi tudo|hey)/.test(text)) {
  fluxo = 'saudacao';
} else if (/(cadastr|novo paciente|primeira vez|nunca vim|novo aqui)/.test(text)) {
  fluxo = 'precadastro';
} else if (/(agendar|consulta|marcar|horário|disponib|agenda)/.test(text)) {
  fluxo = 'agendamento';
} else if (/(exame|resultado|laudo|pdf|enviar exame)/.test(text)) {
  fluxo = 'exames';
} else if (/(urgência|emergência|dor forte|mal|socorro)/.test(text)) {
  fluxo = 'urgencia';
} else if (/(preço|valor|quanto|custo|convênio|plano)/.test(text)) {
  fluxo = 'preco';
} else if (/(programa|acompanhamento|protocolo|30 dias|90 dias)/.test(text)) {
  fluxo = 'acompanhamento';
} else {
  fluxo = 'ia_livre'; // Claude responde livremente
}

return [{ json: { ...$json, fluxo, textOriginal: text } }];

// Formata resposta do Claude
const claudeResponse = $json.content?.[0]?.text || 'Desculpe, não consegui processar sua mensagem. Tente novamente.';
const prevData = $('Detectar Intenção').first().json;

return [{ json: { ...prevData, resposta: claudeResponse } }];
